   119→    public static final int FETCH_MAX_BYTES_DEFAULT = 55 * 1024 * 1024;
   120→    public static final String FETCH_MAX_BYTES_DOC = "The maximum number of bytes we will return for a fetch request. Must be at least 1024.";
