   123→    public static final String MAX_REQUEST_PARTITION_SIZE_LIMIT_CONFIG = "max.request.partition.size.limit";
   124→    public static final int MAX_REQUEST_PARTITION_SIZE_LIMIT_DEFAULT = 2000;
   125→    public static final String MAX_REQUEST_PARTITION_SIZE_LIMIT_DOC = "The maximum number of partitions can be served in one request.";
