   133→    public static final String AUTHORIZER_CLASS_NAME_DEFAULT = "";
   134→    public static final String AUTHORIZER_CLASS_NAME_DOC = "The fully qualified name of a class that implements <code>" +
   135→           Authorizer.class.getName() + "</code> interface, which is used by the broker for authorization.";
